import { React, useState } from 'react'
import useBook from '../hooks/useBook';
import { Outlet, useNavigate } from 'react-router-dom';
import { Button, TextField, Grid } from '@mui/material';
import { FilterList } from '@mui/icons-material';
import appTheme from '../theme';
import axios from 'axios'

const SearchBar = () => {

    const { loading, setLoading, setBookData } = useBook()

    const [search, setSearch] = useState({
        query: ''
    })

    const { query } = search

    const navigate = useNavigate();

    const textFieldStyles = {
        backgroundColor: 'rgba(119,154,74,0.25)',
        padding: '0'
    }

    const getBookList = async datos => {
       
        setLoading(true)

        try{
            const url = "https://www.googleapis.com/books/v1/volumes?q=" + search.query + "&key=AIzaSyAnyZwuyjsG3Ece1XxgbCT5tT2Q7PSZBfE&maxResults=40&printType=books"

            const { data: res } = await axios(url)

            setBookData(res.items)
        
        }
        catch{
            console.log()
        }
        finally{
            setLoading(false)
        }

    
}

    const handleSearch = e => {
        setSearch({
                ...search,
                [e.target.name]: e.target.value
            })
        getBookList(query, loading)
        navigate("list", { replace: true });
    }

  return (
      <>
       
            <Grid container justifyContent="center" alignItems="center" spacing={0} p={2}>
            <Grid item xs={10}>
                <TextField
                fullWidth
                label='Buscar por título, autor...'
                type="text"
                name="query"
                onChange={handleSearch}
                value={query}
                variant="filled"
                size="small"
                sx={textFieldStyles}
                InputProps={{
                    disableUnderline: true,
                    sx: {
                        borderBottom: 'none',
                        
                }
                  }}
                InputLabelProps={{
                    sx: { color: appTheme.palette.primary.dark, fontWeight: '500', fontSize: '14px' }
                }}
                />
            </Grid>
            <Grid item xs={2}>
                <Button type="button" variant="contained" color="primary" style={{borderRadius: '0', maxHeight: '100px'}}  onClick={() => {}}>
                <FilterList sx={{ minHeight: '35px', width: '100%' }}/>
                </Button>
            </Grid>
            
            </Grid>

        <Outlet></Outlet>
      </>
        
  )
}

export default SearchBar
